module div_16bit(
    input clk,
    input rst,
    input sign,
    input [15:0] dividend,
    input [15:0] divisor,
    input opn_valid,
    input res_ready,
    output res_valid,
    output [15:0] result
);
    reg [3:0] cnt;
    reg start_cnt;
    reg [15:0] neg_divisor;
    reg [15:0] sr;
    parameter IDLE = 3'b000;
    parameter SUB = 3'b001;
    parameter SEL = 3'b010;
    parameter SHIFT = 3'b011;
    parameter DONE = 3'b100;
    reg [2:0] state;
    reg [2:0] next_state;
    always @(posedge clk or negedge rst) begin
        if (!rst)
            state <= IDLE;
        else
            state <= next_state;
    end
    always @(*) begin
        case (state)
            IDLE: begin
                if (opn_valid && !res_valid)
                    next_state = SUB;
                else
                    next_state = IDLE;
            end
            SUB: begin
                if (cnt[3])
                    next_state = DONE;
                else
                    next_state = SHIFT;
            end
            SHIFT: begin
                if (cnt[3])
                    next_state = DONE;
                else
                    next_state = SEL;
            end
            SEL: begin
                if (cnt[3])
                    next_state = DONE;
                else
                    next_state = SHIFT;
            end
            DONE: begin
                if (res_valid && res_ready)
                    next_state = IDLE;
                else
                    next_state = DONE;
            end
            default: next_state = IDLE;
        endcase
    end
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            cnt <= 4'b0000;
            start_cnt <= 1'b0;
            neg_divisor <= 16'h0000;
            sr <= 16'h0000;
        end
        else if (opn_valid && !res_valid) begin
            cnt <= 4'b0000;
            start_cnt <= 1'b1;
            neg_divisor <= (sign && divisor[7]) ? {8'b11111111, divisor} : {8'b00000000, ~divisor + 1'b1};
            sr <= (sign && dividend[7]) ? {8'b11111111, dividend, 1'b0} : {8'b00000000, dividend, 1'b0};
        end
        else if (start_cnt && cnt[3]) begin
            cnt <= cnt;
            start_cnt <= start_cnt;
            neg_divisor <= neg_divisor;
            sr <= {sr[14:0], 1'b0};
        end
        else if (start_cnt && !cnt[3]) begin
            cnt <= cnt + 1'b1;
            start_cnt <= start_cnt;
            neg_divisor <= neg_divisor;
            sr <= {sr[14:0], 1'b0};
        end
        else begin
            cnt <= cnt;
            start_cnt <= start_cnt;
            neg_divisor <= neg_divisor;
            sr <= sr;
        end
    end
    assign res_valid = (state == DONE) ? 1'b1 : 1'b0;
    assign result = (sign && (dividend[7] ^ divisor[7])) ? {neg_divisor[15], sr[15:8]} : {neg_divisor[15], sr[7:0]};
endmodule
